// ========================================================
// PARSE MESSAGE — Extrai dados do webhook Evolution API
// Formato Evolution API v2:
// { event, instance, data: { key: { remoteJid, fromMe }, message: { conversation }, messageType } }
// ========================================================
const body = $input.first().json.body || $input.first().json;

// Ignora mensagens enviadas por nós (fromMe)
if (body.data?.key?.fromMe === true) {
  return []; // Para execução — não processar eco
}

// Ignora eventos que não são mensagens
const event = body.event || '';
if (event && !event.includes('messages')) {
  return [];
}

// Extrai instance name
const instance = body.instance || body.instanceName || '';

// Extrai número do remetente
const remoteJid = body.data?.key?.remoteJid || '';
const phone = remoteJid.replace('@s.whatsapp.net', '').replace('@g.us', '').replace(/\D/g, '');

// Ignora grupos (termina com @g.us)
if (remoteJid.includes('@g.us')) {
  return [];
}

// Extrai texto da mensagem
const message = body.data?.message;
let text = '';
if (message?.conversation) {
  text = message.conversation;
} else if (message?.extendedTextMessage?.text) {
  text = message.extendedTextMessage.text;
} else if (message?.imageMessage?.caption) {
  text = message.imageMessage.caption;
} else if (message?.videoMessage?.caption) {
  text = message.videoMessage.caption;
}

// Tipo de mídia
const messageType = body.data?.messageType || 'conversation';
let media_type = null;
let media_url = null;
if (messageType === 'imageMessage') media_type = 'image';
else if (messageType === 'audioMessage') media_type = 'audio';
else if (messageType === 'videoMessage') media_type = 'video';
else if (messageType === 'documentMessage') media_type = 'document';

// Se não tem texto nem mídia, ignorar
if (!text && !media_type) {
  return [];
}

return [{
  json: {
    instance,
    phone,
    remoteJid,
    text: text || '[mídia recebida]',
    media_type,
    media_url,
    messageType,
    timestamp: new Date().toISOString()
  }
}];

// ========================================================
// VALIDATE USER — Verifica se usuário existe e está ativo
// ========================================================
const users = $('Find User by Instance').first().json;
const userArray = Array.isArray(users) ? users : [users];
const phone = $('Parse Message').first().json.phone;
const instance = $('Parse Message').first().json.instance;

if (!userArray.length || !userArray[0]?.id) {
  // Nenhum usuário encontrado para esta instância
  // Tenta busca parcial (instância pode ter sufixo)
  return [{
    json: {
      error: true,
      message: `Nenhum usuário encontrado para instância: ${instance}`,
      phone,
      instance
    }
  }];
}

const user = userArray[0];

if (user.active === false) {
  return [{
    json: {
      error: true,
      message: 'Usuário desativado',
      phone,
      instance
    }
  }];
}

return [{
  json: {
    error: false,
    user_id: user.id,
    display_name: user.display_name,
    evo_instance: user.evo_instance,
    phone,
    instance
  }
}];

// ========================================================
// PROCESS LEAD — Cria lead se não existe, detecta tipo de agente
// ========================================================
const leadResult = $('Find Lead').first().json;
const subResult = $('Get Subscription').first().json;
const userData = $('Validate User').first().json;

const leads = Array.isArray(leadResult) ? leadResult : (leadResult?.id ? [leadResult] : []);
const subs = Array.isArray(subResult) ? subResult : (subResult?.plano ? [subResult] : []);
const subscription = subs[0] || {};

let lead = leads[0] || null;
let is_new_lead = !lead;

// Detecta tipo de agente
const stage = lead?.stage || 'novo_contato';
const fluxo_id = lead?.fluxo_id || '';
const objecoes_count = lead?.objecoes_count || 0;

let agent_type = 'principal';
let agent_index = 0;

if ((stage === 'objecoes' || objecoes_count > 2) && subscription.addon_objecao) {
  agent_type = 'objecao';
} else if (stage === 'prospecao' || fluxo_id?.includes('prospec')) {
  agent_type = 'prospec';
} else if (subscription.agentes_extras > 0 && fluxo_id?.match(/ae(\d)/)) {
  agent_type = 'extra';
  const match = fluxo_id.match(/ae(\d)/);
  agent_index = match ? parseInt(match[1]) : 0;
}

// Verifica saldo de tokens
const has_tokens = (subscription.creditos_tokens || 0) > 0;
const sub_active = subscription.status === 'ativo' || subscription.status === 'active';

return [{
  json: {
    user_id: userData.user_id,
    lead_id: lead?.id || null,
    lead_nome: lead?.nome || null,
    is_new_lead,
    stage,
    fluxo_id,
    agent_type,
    agent_index,
    has_tokens,
    sub_active,
    subscription_status: subscription.status,
    creditos_tokens: subscription.creditos_tokens || 0,
    addon_objecao: subscription.addon_objecao || false,
    agentes_extras: subscription.agentes_extras || 0,
    evo_instance: userData.evo_instance,
    phone: userData.phone
  }
}];

// ========================================================
// MERGE LEAD DATA — Combina lead novo ou existente
// ========================================================
const processData = $('Process Lead').first().json;
const isNew = processData.is_new_lead;

let lead_id = processData.lead_id;

if (isNew) {
  try {
    const created = $('Create Lead').first().json;
    const createdArr = Array.isArray(created) ? created : [created];
    lead_id = createdArr[0]?.id || null;
  } catch(e) {
    // Create Lead não executou (lead existente)
  }
}

return [{
  json: {
    ...processData,
    lead_id,
    is_new_lead: isNew
  }
}];

// ========================================================
// BUILD SYSTEM PROMPT — Monta prompt + seleciona provider/modelo
// Lê configs do agente_config com prefixo por tipo de agente
// ========================================================
const configRaw = $('Busca Configs SDR').first().json;
const configs = Array.isArray(configRaw) ? configRaw : [];
const configMap = {};
configs.forEach(item => {
  if (item.chave && item.valor !== undefined) configMap[item.chave] = item.valor;
});

const agentData = $('Merge Lead Data').first().json;
const agent_type = agentData.agent_type;
const agent_index = agentData.agent_index;

// Prefixo por tipo de agente
const prefix = agent_type === 'principal' ? '' 
  : agent_type === 'prospec' ? 'prospec_' 
  : agent_type === 'objecao' ? 'ob_' 
  : `ae${agent_index}_`;

// Helper: busca config com fallback (prefixo → sem prefixo → default)
function cfg(key, fallback) {
  return configMap[`${prefix}${key}`] || configMap[key] || fallback || '';
}

// ---- PROMPT ----
let sistema_prompt = cfg('sistema_prompt', 'Você é um assistente de vendas profissional. Qualifique leads com base nos critérios definidos. Seja educado, persuasivo e objetivo.');

// Append objetivo
const objetivo = cfg('objetivo');
if (objetivo) sistema_prompt = `OBJETIVO: ${objetivo}\n\n${sistema_prompt}`;

// Append tonalidade
const tonalidade = cfg('tonalidade');
if (tonalidade) sistema_prompt += `\n\nTONALIDADE: ${tonalidade}`;

// Append critérios de qualificação
const criterios = cfg('criterios_qualificacao');
if (criterios) sistema_prompt += `\n\nCRITÉRIOS DE QUALIFICAÇÃO:\n${criterios}`;

// Append instruções de comunicação
const instrucoes = cfg('instrucoes_comunicacao');
if (instrucoes) sistema_prompt += `\n\nINSTRUÇÕES DE COMUNICAÇÃO:\n${instrucoes}`;

// Instruções especiais para tags
sistema_prompt += '\n\nTAGS ESPECIAIS (use quando apropriado):';
sistema_prompt += '\n- [LEAD_QUALIFICADO] — quando o lead atende todos os critérios de qualificação';
sistema_prompt += '\n- [LEAD_DESQUALIFICADO] — quando o lead não tem perfil adequado';
sistema_prompt += '\n- [INICIAR_PAGAMENTO] — quando o lead quer efetuar pagamento';
sistema_prompt += '\n\nIMPORTANTE: Envie mensagens curtas e naturais, como num WhatsApp real. Máximo 3 parágrafos.';

// ---- PROVIDER / MODELO ----
const provider = cfg('ai_provider', 'openai');
let model, temperature, max_tokens;

if (provider === 'openai') {
  model = cfg('openai_model', 'gpt-4o-mini');
  temperature = parseFloat(cfg('openai_temperature', '0.7'));
  max_tokens = parseInt(cfg('openai_max_tokens', '1024'));
} else if (provider === 'claude') {
  model = cfg('claude_model', 'claude-haiku-4-5');
  temperature = parseFloat(cfg('claude_temperature', '0.7'));
  max_tokens = parseInt(cfg('claude_max_tokens', '1024'));
} else if (provider === 'google') {
  model = cfg('google_model', 'gemini-2.0-flash');
  temperature = parseFloat(cfg('google_temperature', '0.7'));
  max_tokens = parseInt(cfg('google_max_tokens', '1024'));
} else {
  model = 'gpt-4o-mini';
  temperature = 0.7;
  max_tokens = 1024;
}

// ---- HISTÓRICO ----
const historyRaw = $('Load History').first().json;
const history = Array.isArray(historyRaw) ? historyRaw : [];
const userMessage = $('Parse Message').first().json.text;

// Monta messages array para LLM
const messages = [{ role: 'system', content: sistema_prompt }];

// Histórico em ordem cronológica (API retorna desc, invertemos)
const historyAsc = [...history].reverse();
for (const msg of historyAsc) {
  messages.push({
    role: msg.sender === 'assistant' ? 'assistant' : 'user',
    content: msg.conteudo
  });
}

// Mensagem atual
messages.push({ role: 'user', content: userMessage });

return [{
  json: {
    provider,
    model,
    temperature,
    max_tokens,
    messages,
    user_id: agentData.user_id,
    msg_qualificado: cfg('msg_qualificado', 'Parabéns! Você foi qualificado. Em breve entraremos em contato.'),
    msg_desqualificado: cfg('msg_desqualificado', 'Obrigado pelo contato! Infelizmente não temos uma solução adequada neste momento.'),
    responder_em_audio: cfg('responder_em_audio', 'false'),
    numero_destino: cfg('numero_destino'),
    grupo_destino: cfg('grupo_destino'),
    notif_destino: configMap['notif_destino'] || 'numero'
  }
}];

// ========================================================
// PROCESS RESPONSE — Processa resposta da LLM
// Detecta qualificação, objeções, pagamento
// Limpa tags internas antes de enviar ao lead
// ========================================================
const llmResponse = $('LLM Call').first().json;
const response_text = llmResponse.content || llmResponse.choices?.[0]?.message?.content || '';
const promptData = $('Build Prompt + History').first().json;
const userText = ($('Parse Message').first().json.text || '').toLowerCase();
const agentData = $('Merge Lead Data').first().json;

// ---- DETECTA QUALIFICAÇÃO ----
const has_qualificado = response_text.includes('[LEAD_QUALIFICADO]');
const has_desqualificado = response_text.includes('[LEAD_DESQUALIFICADO]');
const has_pagamento = response_text.includes('[INICIAR_PAGAMENTO]');

// ---- DETECTA OBJEÇÕES (na mensagem do usuário) ----
const objection_keywords = ['não posso', 'muito caro', 'não sei', 'concorrente', 'depois', 'não tenho', 'sem interesse', 'tá caro', 'está caro', 'acho caro'];
let has_objection = false;
let objection_type = '';
for (const keyword of objection_keywords) {
  if (userText.includes(keyword)) {
    has_objection = true;
    if (keyword.includes('caro') || keyword.includes('não tenho')) objection_type = 'preco';
    else if (keyword.includes('depois')) objection_type = 'timing';
    else if (keyword.includes('concorrente')) objection_type = 'concorrente';
    else if (keyword.includes('sem interesse')) objection_type = 'interesse';
    else objection_type = 'outro';
    break;
  }
}

// ---- LIMPA TAGS DA RESPOSTA ----
let clean_response = response_text
  .replace(/\[LEAD_QUALIFICADO\]/g, '')
  .replace(/\[LEAD_DESQUALIFICADO\]/g, '')
  .replace(/\[INICIAR_PAGAMENTO\]/g, '')
  .trim();

// ---- CALCULA NOVO STAGE ----
let new_stage = agentData.stage;
if (has_qualificado) new_stage = 'qualificado';
else if (has_desqualificado) new_stage = 'nao_qualificado';
else if (agentData.stage === 'novo_contato') new_stage = 'em_atendimento';

return [{
  json: {
    response_text: clean_response,
    qualified: has_qualificado,
    disqualified: has_desqualificado,
    payment_intent: has_pagamento,
    has_objection,
    objection_type,
    new_stage,
    responder_em_audio: promptData.responder_em_audio === 'true',
    tokens_used: llmResponse.deducted_tokens || llmResponse.usage?.total_tokens || 0,
    msg_qualificado: promptData.msg_qualificado,
    msg_desqualificado: promptData.msg_desqualificado,
    numero_destino: promptData.numero_destino,
    grupo_destino: promptData.grupo_destino,
    notif_destino: promptData.notif_destino
  }
}];
